class SaperField{constructor(t,e,i){this.condition=0,this.gameController=i,this.x=t,this.y=e,this.mine=!1,this.mineCounter=0,this.blockNode=!1,this.createNode()}hasMine(){return this.mine}setMine(){this.mine=!0}showMine(){this.node.dataset.hasMine=!0,this.node.textContent="*"}increaseMineCounter(){this.mineCounter+=1}createNode(){this.node=document.createElement("div"),this.node.className="game-play__board-field",this.node.dataset.x=this.x,this.node.dataset.y=this.y,this.node.dataset.discovered=!1,this.node.dataset.hasMine=!1,this.node.addEventListener("click",t=>this.handleLeftClick(t)),this.node.addEventListener("contextmenu",t=>this.handleRightClick(t))}getNode(){return this.node}isBlockNode(){return this.blockNode}setNodeBlock(){this.blockNode=!0}deselect(){this.node.textContent="",this.condition=0,this.gameController.deselectField(this.x,this.y)}select(){this.node.textContent="*",this.condition=1,this.gameController.selectField(this.x,this.y)}isSelected(){return 1===this.condition}discover(t=!1){return 2!==this.condition&&(this.hasMine()?(this.gameController.gameOver(),!1):(1===this.condition&&this.deselect(),this.condition=2,this.node.textContent=0===this.mineCounter?"":this.mineCounter,this.node.dataset.discovered=!0,void this.gameController.discoverField(this.x,this.y,this.mineCounter)))}handleLeftClick(t){if(t.preventDefault(),this.isBlockNode())return!1;2===this.condition?this.gameController.shiftDiscover(this.x,this.y):this.discover()}handleRightClick(t){if(t.preventDefault(),this.isBlockNode())return!1;0===this.condition?this.select():1===this.condition&&this.deselect()}}